--preset--spacing--md)","bottom":"var(--wp--preset--spacing--md)","left":"var(--wp--preset--spacing--md)","right":"var(--wp--preset--spacing--md)"}},"color":{"background":"#ffffff"}},"layout":{"type":"flex","orientation":"vertical"}} --><div class="wp-block-group has-background" style="background-color:#ffffff;border-radius:8px;border:1px solid var(--wp--preset--color--gray-200);padding:var(--wp--preset--spacing--md)"><!-- wp:html --><div style="width:48px;height:48px;background:var(--wp--preset--color--blue-100);border-radius:8px;display:flex;align-items:center;justify-content:center;margin-bottom:var(--wp--preset--spacing--sm)"><i class="fa-solid fa-chess" style="color:var(--wp--preset--color--ocean-blue);font-size:1.25rem"></i></div><!-- /wp:html --><!-- wp:heading {"level":3,"fontSize":"medium"} --><h3 class="wp-block-heading has-medium-font-size">AI Strategy Development</h3><!-- /wp:heading --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"}}} --><p style="color:var(--wp--preset--color--gray-600)">We audit your current process, identify automation opportunities, and build a prioritised roadmap aligned to your revenue goals.</p><!-- /wp:paragraph --></div><!-- /wp:group --></div><!-- /wp:column --><!-- wp:column --><div class="wp-block-column"><!-- wp:group {"style":{"border":{"width":"1px","color":"var(--wp--preset--color--gray-200)","radius":"8px"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--md)","bottom":"var(--wp--preset--spacing--md)","left":"var(--wp--preset--spacing--md)","right":"var(--wp--preset--spacing--md)"}},"color":{"background":"#ffffff"}},"layout":{"type":"flex","orientation":"vertical"}} --><div class="wp-block-group has-background" style="background-color:#ffffff;border-radius:8px;border:1px solid var(--wp--preset--color--gray-200);padding:var(--wp--preset--spacing--md)"><!-- wp:html --><div style="width:48px;height:48px;background:var(--wp--preset--color--blue-100);border-radius:8px;display:flex;ali