		'post_name'    => 'case-studies',
		'post_content' => '<!-- wp:group {"align":"full","style":{"color":{"background":"var(--wp--preset--color--platinum-white)"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--2xl)","bottom":"var(--wp--preset--spacing--2xl)"}}},"layout":{"type":"constrained"}} --><div class="wp-block-group alignfull has-background" style="background-color:var(--wp--preset--color--platinum-white);padding-top:var(--wp--preset--spacing--2xl);padding-bottom:var(--wp--preset--spacing--2xl)"><!-- wp:heading {"textAlign":"center","level":1,"fontSize":"xx-large"} --><h1 class="wp-block-heading has-text-align-center has-xx-large-font-size">Success Stories That Drive Results</h1><!-- /wp:heading --><!-- wp:paragraph {"align":"center","style":{"color":{"text":"var(--wp--preset--color--gray-600)"},"spacing":{"margin":{"bottom":"var(--wp--preset--spacing--md)"}}}} --><p class="has-text-align-center" style="color:var(--wp--preset--color--gray-600);margin-bottom:var(--wp--preset--spacing--md)">Real results from real companies. See how Sales Compass has helped businesses across industries accelerate growth.</p><!-- /wp:paragraph --><!-- wp:buttons {"layout":{"type":"flex","justifyContent":"center"}} --><div class="wp-block-buttons"><!-- wp:button --><div class="wp-block-button"><a class="wp-block-button__link wp-element-button" href="#case-studies-grid">Explore Case Studies</a></div><!-- /wp:button --></div><!-- /wp:buttons --></div><!-- /wp:group --><!-- wp:pattern {"slug":"salescompass/featured-case-study"} /--><div id="case-studies-grid"><!-- wp:pattern {"slug":"salescompass/case-study-cards"} /--></div><!-- wp:pattern {"slug":"salescompass/stats-band"} /--><!-- wp:pattern {"slug":"salescompass/testimonials"} /--><!-- wp:group {"align":"full","style":{"color":{"background":"var(--wp--preset--color--ocean-blue)"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--2xl)","bottom":"var(--wp--preset--spacing--2xl)"}}},"layout":{"type":"constrained"}} --><div class="wp-block-group alignfull has-background" style="background-color:var(--wp--preset--color--ocean-blue);padding-top:var(--wp--preset--spacing--2xl);padding-bottom:var(--wp--preset--spacing--2xl)"><!-- wp:heading {"textAlign":"center","level":2,"fontSize":"x-large","style":{"color":{"text":"#ffffff"}}} --><h2 class="wp-block-heading has-text-align-center has-x-large-font-size" style="color:#ffffff">Ready to Transform Your Sales Process?</h2><!-- /wp:heading --><!-- wp:paragraph {"align":"center","style":{"color":{"text":"#BFDBFE"},"spacing":{"margin":{"bottom":"var(--wp--preset--spacing--lg)"}}}} --><p class="has-text-align-center" style="color:#BFDBFE;margin-bottom:var(--wp--preset--spacing--lg)">Take the first step toward sales excellence.</p><!-- /wp:paragraph --><!-- wp:buttons {"layout":{"type":"flex","justifyContent":"center"}} --><div class="wp-block-buttons"><!-- wp:button {"style":{"color":{"background":"#ffffff","text":"var(--wp--preset--color--ocean-blue)"}}} --><div class="wp-block-button"><a class="wp-block-button__link wp-element-button" href="/contact/" style="background-color:#ffffff;color:var(--wp--preset--color--ocean-blue)">Book a Consultation</a></div><!-- /wp:button --></div><!-- /wp:buttons --></div><!-- /wp:group -->',
	],

	// -------------------------------------------------------------------------
