	[
		'post_title'   => 'Contact',
		'post_name'    => 'contact',
		'post_content' => '<!-- wp:group {"align":"full","style":{"color":{"background":"var(--wp--preset--color--platinum-white)"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--2xl)","bottom":"var(--wp--preset--spacing--2xl)"}}},"layout":{"type":"constrained"}} --><div class="wp-block-group alignfull has-background" style="background-color:var(--wp--preset--color--platinum-white);padding-top:var(--wp--preset--spacing--2xl);padding-bottom:var(--wp--preset--spacing--2xl)"><!-- wp:columns {"isStackedOnMobile":true,"style":{"spacing":{"blockGap":{"top":"var(--wp--preset--spacing--xl)","left":"var(--wp--preset--spacing--xl)"}}}} --><div class="wp-block-columns is-layout-flex"><!-- wp:column {"width":"55%","verticalAlignment":"center"} --><div class="wp-block-column is-vertically-aligned-center" style="flex-basis:55%"><!-- wp:heading {"level":1,"fontSize":"xx-large"} --><h1 class="wp-block-heading has-xx-large-font-size">Get in Touch</h1><!-- /wp:heading --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"},"spacing":{"margin":{"bottom":"var(--wp--preset--spacing--lg)"}},"typography":{"fontSize":"1.125rem"}}} --><p style="color:var(--wp--preset--color--gray-600);font-size:1.125rem;margin-bottom:var(--wp--preset--spacing--lg)">Have a question or ready to get started? Our team responds within one business day.</p><!-- /wp:paragraph --><!-- wp:buttons {"style":{"spacing":{"blockGap":"var(--wp--preset--spacing--sm)"}}} --><div class="wp-block-buttons"><!-- wp:button --><div class="wp-block-button"><a class="wp-block-button__link wp-element-button" href="#contact-form">Send a Message</a></div><!-- /wp:button --><!-- wp:button {"className":"is-style-outline"} --><div class="wp-block-button is-style-outline"><a class="wp-block-button__link wp-element-button" href="/services/">View Services</a></div><!-- /wp:button --></div><!-- /wp:buttons --></div><!-- /wp:column --><!-- wp:column {"width":"45%","verticalAlignment":"center"} --><div class="wp-block-column is-vertically-aligned-center" style="flex-basis:45%"><!-- wp:image {"id":23,"sizeSlug":"large","linkDestination":"none","style":{"border":{"radius":"12px"}}} --><figure class="wp-block-image size-large" style="border-radius:12px"><img src="http://localhost:8882/wp-content/uploads/2026/06/contact-hero.jpg" alt="Sales Compass team ready to help" class="wp-image-23" style="border-radius:12px"/></figure><!-- /wp:image --></div><!-- /wp:column --></div><!-- /wp:columns --></div><!-- /wp:group --><!-- wp:group {"align":"full","style":{"spacing":{"padding":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--xl)"}}},"layout":{"type":"constrained"}} --><div class="wp-block-group alignfull" style="padding-top:var(--wp--preset--spacing--xl);padding-bottom:var(--wp--preset--spacing--xl)"><!-- wp:columns {"isStackedOnMobile":true,"style":{"spacing":{"blockGap":{"left":"var(--wp--preset--spacing--xl)"}}}} --><div class="wp-block-columns is-layout-flex"><!-- wp:column {"width":"40%"} --><div class="wp-block-column" style="flex-basis:40%"><!-- wp:pattern {"slug":"salescompass/contact-info"} /--></div><!-- /wp:column --><!-- wp:column {"width":"60%"} --><div class="wp-block-column" style="flex-basis:60%"><!-- wp:group {"style":{"border":{"width":"1px","color":"var(--wp--preset--color--gray-200)","radius":"8px"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--lg)","bottom":"var(--wp--preset--spacing--lg)","left":"var(--wp--preset--spacing--lg)","right":"var(--wp--preset--spacing--lg)"}},"color":{"background":"#ffffff"}}} --><div class="wp-block-group has-background" style="background-color:#ffffff;border-radius:8px;border:1px solid var(--wp--preset--color--gray-200);padding:var(--wp--preset--spacing--lg)"><!-- wp:heading {"level":3,"fontSize":"large"} --><h3 class="wp-block-heading has-large-font-size">Send Us a Message</h3><!-- /wp:heading --><!-- wp:paragraph --><p><em>Inquiry form will be embedded here (SCW-53).</em></p><!-- /wp:paragraph --></div><!-- /wp:group --></div><!-- /wp:column --></div><!-- /wp:columns --></div><!-- /wp:group --><!-- wp:group {"align":"full","style":{"color":{"background":"var(--wp--preset--color--platinum-white)"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--xl)"}}},"layout":{"type":"constrained"}} --><div class="wp-block-group alignfull has-background" style="background-color:var(--wp--preset--color--platinum-white);padding-top:var(--wp--preset--spacing--xl);padding-bottom:var(--wp--preset--spacing--xl)"><!-- wp:heading {"textAlign":"center","level":2,"fontSize":"x-large","style":{"spacing":{"margin":{"bottom":"var(--wp--preset--spacing--xl)"}}}} --><h2 class="wp-block-heading has-text-align-center has-x-large-font-size" style="margin-bottom:var(--wp--preset--spacing--xl)">Frequently Asked Questions</h2><!-- /wp:heading --><!-- wp:group {"style":{"layout":{"selfStretch":"fixed","flexSize":"800px"},"spacing":{"blockGap":"var(--wp--preset--spacing--sm)"}},"layout":{"type":"flex","orientation":"vertical","justifyContent":"center"}} --><div class="wp-block-group" style="max-width:800px;margin-inline:auto"><!-- wp:details {"style":{"border":{"width":"1px","color":"var(--wp--preset--color--gray-200)","radius":"8px"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--md)","bottom":"var(--wp--preset--spacing--md)","left":"var(--wp--preset--spacing--md)","right":"var(--wp--preset--spacing--md)"}},"color":{"background":"#ffffff"}}} --><details class="wp-block-details has-background" style="background-color:#ffffff;border-radius:8px;border:1px solid var(--wp--preset--color--gray-200);padding:var(--wp--preset--spacing--md)"><summary>How quickly can I expect results?</summary><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"},"spacing":{"margin":{"top":"var(--wp--preset--spacing--sm)"}}}} --><p style="color:var(--wp--preset--color--gray-600);margin-top:var(--wp--preset--spacing--sm)">Most clients begin seeing measurable improvements within 4–6 weeks. Significant results typically emerge over a 90-day engagement as strategies are refined and embedded into daily habits.</p><!-- /wp:paragraph --></details><!-- /wp:details --><!-- wp:details {"style":{"border":{"width":"1px","color":"var(--wp--preset--color--gray-200)","radius":"8px"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--md)","bottom":"var(--wp--preset--spacing--md)","left":"var(--wp--preset--spacing--md)","right":"var(--wp--preset--spacing--md)"}},"color":{"background":"#ffffff"}}} --><details class="wp-block-details has-background" style="background-color:#ffffff;border-radius:8px;border:1px solid var(--wp--preset--color--gray-200);padding:var(--wp--preset--spacing--md)"><summary>Do you offer customised solutions?</summary><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"},"spacing":{"margin":{"top":"var(--wp--preset--spacing--sm)"}}}} --><p style="color:var(--wp--preset--color--gray-600);margin-top:var(--wp--preset--spacing--sm)">Yes. Every engagement is scoped around your specific market, team size, and goals. We do not offer off-the-shelf packages — everything is tailored.</p><!-- /wp:paragraph --></details><!-- /wp:details --><!-- wp:details {"style":{"border":{"width":"1px","color":"var(--wp--preset--color--gray-200)","radius":"8px"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--md)","bottom":"var(--wp--preset--spacing--md)","left":"var(--wp--preset--spacing--md)","right":"var(--wp--preset--spacing--md)"}},"color":{"background":"#ffffff"}}} --><details class="wp-block-details has-background" style="background-color:#ffffff;border-radius:8px;border:1px solid var(--wp--preset--color--gray-200);padding:var(--wp--preset--spacing--md)"><summary>What is the typical onboarding process?</summary><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"},"spacing":{"margin":{"top":"var(--wp--preset--spacing--sm)"}}}} --><p style="color:var(--wp--preset--color--gray-600);margin-top:var(--wp--preset--spacing--sm)">Onboarding typically takes 2–3 weeks and includes an initial assessment, goal-setting session, and delivery plan. We aim to have your first results session within 30 days of kick-off.</p><!-- /wp:paragraph --></details><!-- /wp:details --></div><!-- /wp:group --></div><!-- /wp:group --><!-- wp:group {"align":"full","style":{"color":{"background":"var(--wp--preset--color--platinum-white)"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--xl)"}}},"layout":{"type":"constrained"}} --><div class="wp-block-group alignfull has-background" style="background-color:var(--wp--preset--color--platinum-white);padding-top:var(--wp--preset--spacing--xl);padding-bottom:var(--wp--preset--spacing--xl)"><!-- wp:heading {"textAlign":"center","level":2,"fontSize":"x-large","style":{"spacing":{"margin":{"bottom":"var(--wp--preset--spacing--xl)"}}}} --><h2 class="wp-block-heading has-text-align-center has-x-large-font-size" style="margin-bottom:var(--wp--preset--spacing--xl)">Our Office</h2><!-- /wp:heading --><!-- wp:columns {"isStackedOnMobile":true,"style":{"spacing":{"blockGap":{"left":"var(--wp--preset--spacing--xl)"}}}} --><div class="wp-block-columns is-layout-flex"><!-- wp:column {"width":"55%"} --><div class="wp-block-column" style="flex-basis:55%"><!-- wp:image {"id":24,"sizeSlug":"large","linkDestination":"none","style":{"border":{"radius":"12px"}}} --><figure class="wp-block-image size-large" style="border-radius:12px"><img src="http://localhost:8882/wp-content/uploads/2026/06/contact-map.png" alt="Sales Compass office location" class="wp-image-24" style="border-radius:12px"/></figure><!-- /wp:image --></div><!-- /wp:column --><!-- wp:column {"width":"45%","verticalAlignment":"center"} --><div class="wp-block-column is-vertically-aligned-center" style="flex-basis:45%"><!-- wp:heading {"level":3,"fontSize":"large"} --><h3 class="wp-block-heading has-large-font-size">Sales Compass Headquarters</h3><!-- /wp:heading --><!-- wp:html --><div style="display:flex;flex-direction:column;gap:var(--wp--preset--spacing--md)"><div style="display:flex;gap:0.75rem"><i class="fa-solid fa-location-dot" style="color:var(--wp--preset--color--ocean-blue);margin-top:3px"></i><span style="color:var(--wp--preset--color--gray-600)">123 Business Avenue, Suite 200<br>San Francisco, CA 94107</span></div><div style="display:flex;gap:0.75rem"><i class="fa-solid fa-clock" style="color:var(--wp--preset--color--ocean-blue);margin-top:3px"></i><span style="color:var(--wp--preset--color--gray-600)">Mon–Fri 9am–6pm<br>Sat–Sun Closed</span></div></div><!-- /wp:html --><!-- wp:buttons {"style":{"spacing":{"margin":{"top":"var(--wp--preset--spacing--md)"}}}} --><div class="wp-block-buttons"><!-- wp:button {"className":"is-style-outline"} --><div class="wp-block-button is-style-outline"><a class="wp-block-button__link wp-element-button" href="https://maps.google.com" target="_blank" rel="noopener">Get Directions</a></div><!-- /wp:button --></div><!-- /wp:buttons --></div><!-- /wp:column --></div><!-- /wp:columns --></div><!-- /wp:group --><!-- wp:group {"align":"full","style":{"color":{"background":"var(--wp--preset--color--ocean-blue)"},"spacing":{"padding":{"top":"var(--wp--preset--spacing--2xl)","bottom":"var(--wp--preset--spacing--2xl)"}}},"layout":{"type":"constrained"}} --><div class="wp-block-group alignfull has-background" style="background-color:var(--wp--preset--color--ocean-blue);padding-top:var(--wp--preset--spacing--2xl);padding-bottom:var(--wp--preset--spacing--2xl)"><!-- wp:heading {"textAlign":"center","level":2,"fontSize":"x-large","style":{"color":{"text":"#ffffff"}}} --><h2 class="wp-block-heading has-text-align-center has-x-large-font-size" style="color:#ffffff">Ready to Transform Your Sales Process?</h2><!-- /wp:heading --><!-- wp:paragraph {"align":"center","style":{"color":{"text":"#BFDBFE"},"spacing":{"margin":{"bottom":"var(--wp--preset--spacing--lg)"}}}} --><p class="has-text-align-center" style="color:#BFDBFE;margin-bottom:var(--wp--preset--spacing--lg)">Take the first step toward sales excellence.</p><!-- /wp:paragraph --><!-- wp:buttons {"layout":{"type":"flex","justifyContent":"center"}} --><div class="wp-block-buttons"><!-- wp:button {"style":{"color":{"background":"#ffffff","text":"var(--wp--preset--color--ocean-blue)"}}} --><div class="wp-block-button"><a class="wp-block-button__link wp-element-button" href="/contact/" style="background-color:#ffffff;color:var(--wp--preset--color--ocean-blue)">Book a Consultation</a></div><!-- /wp:button --></div><!-- /wp:buttons --></div><!-- /wp:group -->',
