	// -------------------------------------------------------------------------
	// SCW-49 — Privacy Policy  (updates existing ID 3)
	// -------------------------------------------------------------------------
	[
		'post_title'   => 'Privacy Policy',
		'post_name'    => 'privacy-policy',
		'post_content' => '<!-- wp:group {"align":"full","style":{"spacing":{"padding":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--2xl)"}}},"layout":{"type":"constrained","contentSize":"860px"}} --><div class="wp-block-group alignfull" style="padding-top:var(--wp--preset--spacing--xl);padding-bottom:var(--wp--preset--spacing--2xl)"><!-- wp:heading {"level":1,"fontSize":"xx-large"} --><h1 class="wp-block-heading has-xx-large-font-size">Privacy Policy</h1><!-- /wp:heading --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-500)"},"spacing":{"margin":{"bottom":"var(--wp--preset--spacing--xl)"}}}} --><p style="color:var(--wp--preset--color--gray-500);margin-bottom:var(--wp--preset--spacing--xl)">Last Updated: May 18, 2026</p><!-- /wp:paragraph --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"}}} --><p style="color:var(--wp--preset--color--gray-600)">At Sales Compass, we are committed to protecting your privacy. This Privacy Policy explains how we collect, use, and safeguard your personal information when you visit our website or use our services.</p><!-- /wp:paragraph --><!-- wp:heading {"level":2,"fontSize":"large","style":{"spacing":{"margin":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--sm)"}}}} --><h2 class="wp-block-heading has-large-font-size" style="margin-top:var(--wp--preset--spacing--xl);margin-bottom:var(--wp--preset--spacing--sm)">Information We Collect</h2><!-- /wp:heading --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"}}} --><p style="color:var(--wp--preset--color--gray-600)">We collect information that you provide directly to us, such as when you fill out a contact form, subscribe to our newsletter, or communicate with us. This may include your name, email address, and company information.</p><!-- /wp:paragraph --><!-- wp:heading {"level":2,"fontSize":"large","style":{"spacing":{"margin":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--sm)"}}}} --><h2 class="wp-block-heading has-large-font-size" style="margin-top:var(--wp--preset--spacing--xl);margin-bottom:var(--wp--preset--spacing--sm)">How We Use Your Information</h2><!-- /wp:heading --><!-- wp:list {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"}}} --><ul class="wp-block-list" style="color:var(--wp--preset--color--gray-600)"><!-- wp:list-item --><li>Provide and maintain our services</li><!-- /wp:list-item --><!-- wp:list-item --><li>Respond to your inquiries and support requests</li><!-- /wp:list-item --><!-- wp:list-item --><li>Send you updates and marketing communications</li><!-- /wp:list-item --><!-- wp:list-item --><li>Improve our website and user experience</li><!-- /wp:list-item --><!-- wp:list-item --><li>Comply with legal obligations</li><!-- /wp:list-item --></ul><!-- /wp:list --><!-- wp:heading {"level":2,"fontSize":"large","style":{"spacing":{"margin":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--sm)"}}}} --><h2 class="wp-block-heading has-large-font-size" style="margin-top:var(--wp--preset--spacing--xl);margin-bottom:var(--wp--preset--spacing--sm)">Data Protection</h2><!-- /wp:heading --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"}}} --><p style="color:var(--wp--preset--color--gray-600)">We implement appropriate technical and organizational measures to protect your personal information against unauthorized access, disclosure, or destruction.</p><!-- /wp:paragraph --><!-- wp:heading {"level":2,"fontSize":"large","style":{"spacing":{"margin":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--sm)"}}}} --><h2 class="wp-block-heading has-large-font-size" style="margin-top:var(--wp--preset--spacing--xl);margin-bottom:var(--wp--preset--spacing--sm)">Your Rights</h2><!-- /wp:heading --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"}}} --><p style="color:var(--wp--preset--color--gray-600)">You may have the right to access, correct, or delete your data. Contact us at <a href="mailto:info@salescompass.net">info@salescompass.net</a>.</p><!-- /wp:paragraph --><!-- wp:heading {"level":2,"fontSize":"large","style":{"spacing":{"margin":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--sm)"}}}} --><h2 class="wp-block-heading has-large-font-size" style="margin-top:var(--wp--preset--spacing--xl);margin-bottom:var(--wp--preset--spacing--sm)">Changes to This Policy</h2><!-- /wp:heading --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"}}} --><p style="color:var(--wp--preset--color--gray-600)">We may update this policy from time to time and will notify you by posting changes here.</p><!-- /wp:paragraph --></div><!-- /wp:group -->',
	],

	// -------------------------------------------------------------------------
