	[
		'post_title'   => 'Terms of Service',
		'post_name'    => 'terms-of-service',
		'post_content' => '<!-- wp:group {"align":"full","style":{"spacing":{"padding":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--2xl)"}}},"layout":{"type":"constrained","contentSize":"860px"}} --><div class="wp-block-group alignfull" style="padding-top:var(--wp--preset--spacing--xl);padding-bottom:var(--wp--preset--spacing--2xl)"><!-- wp:heading {"level":1,"fontSize":"xx-large"} --><h1 class="wp-block-heading has-xx-large-font-size">Terms of Service</h1><!-- /wp:heading --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-500)"},"spacing":{"margin":{"bottom":"var(--wp--preset--spacing--xl)"}}}} --><p style="color:var(--wp--preset--color--gray-500);margin-bottom:var(--wp--preset--spacing--xl)">Last Updated: May 18, 2026</p><!-- /wp:paragraph --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"}}} --><p style="color:var(--wp--preset--color--gray-600)">By accessing or using the Sales Compass website and services, you agree to be bound by these Terms of Service. Please read them carefully.</p><!-- /wp:paragraph --><!-- wp:heading {"level":2,"fontSize":"large","style":{"spacing":{"margin":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--sm)"}}}} --><h2 class="wp-block-heading has-large-font-size" style="margin-top:var(--wp--preset--spacing--xl);margin-bottom:var(--wp--preset--spacing--sm)">Use of Services</h2><!-- /wp:heading --><!-- wp:paragraph {"style":{"color":{"text":"var(--wp--preset--color--gray-600)"}}} --><p style="color:var(--wp--preset--color--gray-600)">You agree to use our services only for lawful purposes and in accordance with these Terms. You must not use our services to violate any applicable laws or regulations.</p><!-- /wp:paragraph --><!-- wp:heading {"level":2,"fontSize":"large","style":{"spacing":{"margin":{"top":"var(--wp--preset--spacing--xl)","bottom":"var(--wp--preset--spacing--sm)"}}}} --><h2 class="wp-block-heading has-large-font-si