// =============================================================================
// Upsert each page
// =============================================================================

foreach ( $pages as $data ) {
	$slug     = $data['post_name'];
	$existing = get_page_by_path( $slug );

	if ( $existing ) {
		$result = wp_update_post( [
			'ID'           => $existing->ID,
			'post_title'   => $data['post_title'],
			'post_content' => $data['post_content'],
			'post_status'  => 'publish',
		], true );
		$id = $existing->ID;
	} else {
		$result = wp_insert_post( [
			'post_title'   => $data['post_title'],
			'post_name'    => $slug,
			'post_content' => $data['post_content'],
			'post_status'  => 'publish',
			'post_type'    => 'page',
		], true );
		$id = $result;
	}

	if ( is_wp_error( $result ) ) {
		echo "ERROR '{$slug}': " . $result->get_error_message() . "\n";
		continue;
	}

	update_post_meta( $id, '_wp_page_template', 'page-no-title' );
	echo "Page '{$slug}': OK (ID {$id})\n";
}

// =============================================================================
// Reading settings — static front page
// =============================================================================

$home = get_page_by_path( 'home' );
if ( $home ) {
	update_option( 'show_on_front', 'page' );
	update_option( 'page_on_front', $home->ID );
	echo "Reading settings: front page = home (ID {$home->ID})\n";
} else {
	echo "WARNING: 'home' page not found — reading settings not updated.\n";
}

echo "Done.\n";
